import logging
import json
import hashlib
from datetime import datetime
from elasticsearch import Elasticsearch
from elasticsearch.exceptions import ConnectionError, TransportError
from elasticsearch.helpers import bulk
import os

# Configure logging
logging.basicConfig(
    level=logging.INFO,
    format='%(asctime)s - %(name)s - %(levelname)s - %(message)s',
    handlers=[
        logging.FileHandler('app.log'),
        logging.StreamHandler()
    ]
)
logger = logging.getLogger(__name__)

class SecureElasticsearchClient:
    def __init__(self, hosts=None, use_ssl=False, verify_certs=True, 
                 username=None, password=None, api_key=None):
        if hosts is None:
            hosts = [{'host': 'localhost', 'port': 9200}]
        
        # Security configuration
        es_config = {
            'hosts': hosts,
            'use_ssl': use_ssl,
            'verify_certs': verify_certs,
            'timeout': 30,
            'max_retries': 3,
            'retry_on_timeout': True
        }
        
        # Authentication
        if api_key:
            es_config['api_key'] = api_key
        elif username and password:
            es_config['http_auth'] = (username, password)
        
        try:
            self.es = Elasticsearch(**es_config)
            # Test connection
            if not self.es.ping():
                raise ConnectionError("Failed to connect to Elasticsearch")
            logger.info("Successfully connected to Elasticsearch")
        except Exception as e:
            logger.error(f"Failed to connect to Elasticsearch: {e}")
            raise

    def index_document(self, index_name, document, doc_id=None):
        """Index a document with security checks"""
        try:
            # Sanitize document
            sanitized_doc = self._sanitize_document(document)
            
            # Add timestamp
            sanitized_doc['@timestamp'] = datetime.utcnow().isoformat()
            
            # Index document
            response = self.es.index(
                index=index_name,
                body=sanitized_doc,
                id=doc_id,
                refresh='wait_for'
            )
            
            logger.info(f"Document indexed successfully: {response['result']}")
            return response
            
        except TransportError as e:
            logger.error(f"Transport error during indexing: {e}")
            raise
        except Exception as e:
            logger.error(f"Error indexing document: {e}")
            raise

    def search_documents(self, index_name, query, size=100):
        """Search documents with security checks"""
        try:
            # Validate index name
            if not self._is_valid_index_name(index_name):
                raise ValueError("Invalid index name")
            
            # Build search query
            search_body = {
                "query": query,
                "size": size
            }
            
            response = self.es.search(
                index=index_name,
                body=search_body
            )
            
            logger.info(f"Search completed: {response['hits']['total']['value']} results")
            return response
            
        except TransportError as e:
            logger.error(f"Transport error during search: {e}")
            raise
        except Exception as e:
            logger.error(f"Error during search: {e}")
            raise

    def bulk_index_documents(self, index_name, documents):
        """Bulk index documents"""
        try:
            actions = [
                {
                    "_index": index_name,
                    "_source": self._sanitize_document(doc)
                }
                for doc in documents
            ]
            
            response = bulk(self.es, actions, max_retries=3)
            logger.info(f"Bulk indexing completed: {len(documents)} documents")
            return response
            
        except Exception as e:
            logger.error(f"Error during bulk indexing: {e}")
            raise

    def aggregate_logs(self, index_name, aggregation_query):
        """Perform log aggregation"""
        try:
            response = self.es.search(
                index=index_name,
                body=aggregation_query
            )
            return response
            
        except Exception as e:
            logger.error(f"Error during log aggregation: {e}")
            raise

    def _sanitize_document(self, document):
        """Sanitize document to prevent injection attacks"""
        if not isinstance(document, dict):
            return {'message': str(document)}
        
        sanitized = {}
        for key, value in document.items():
            # Sanitize key names
            safe_key = ''.join(c for c in key if c.isalnum() or c in ['_', '.', '-'])
            if safe_key:
                sanitized[safe_key] = value
        return sanitized

    def _is_valid_index_name(self, index_name):
        """Validate index name"""
        if not isinstance(index_name, str):
            return False
        if len(index_name) == 0:
            return False
        if index_name.startswith('.'):
            return False
        if not all(c.isalnum() or c in ['_', '-', '.'] for c in index_name):
            return False
        return True

    def close(self):
        """Close Elasticsearch connection"""
        if hasattr(self, 'es'):
            self.es.close()
            logger.info("Elasticsearch connection closed")

# Example usage
def main():
    try:
        # Initialize secure Elasticsearch client
        es_client = SecureElasticsearchClient(
            hosts=[{'host': 'localhost', 'port': 9200}],
            username=os.getenv('ES_USERNAME'),
            password=os.getenv('ES_PASSWORD')
        )
        
        # Example document
        log_document = {
            "level": "INFO",
            "message": "User login successful",
            "user_id": "12345",
            "ip_address": "192.168.1.1",
            "timestamp": datetime.utcnow().isoformat()
        }
        
        # Index document
        es_client.index_document("logs", log_document)
        
        # Search documents
        search_query = {
            "match": {
                "message": "login"
            }
        }
        results = es_client.search_documents("logs", search_query)
        print(json.dumps(results, indent=2, default=str))
        
        # Aggregate logs
        aggregation_query = {
            "aggs": {
                "levels": {
                    "terms": {
                        "field": "level"
                    }
                }
            }
        }
        agg_results = es_client.aggregate_logs("logs", aggregation_query)
        print(json.dumps(agg_results, indent=2, default=str))
        
        # Close connection
        es_client.close()
        
    except Exception as e:
        logger.error(f"Application error: {e}")

